// api/v1beta1/clusterpodplacementconfig_webhook_test.go

package v1beta1

import (
	"context"
	"testing"

	"github.com/openshift/multiarch-tuning-operator/api/common/plugins"
)

func TestValidateCreateAndUpdate(t *testing.T) {
	validator := &ClusterPodPlacementConfigValidator{}

	tests := []struct {
		name    string
		cppc    *ClusterPodPlacementConfig
		wantErr bool
	}{
		{
			name: "nil plugins passes validation",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: nil,
				},
			},
			wantErr: false,
		},
		{
			name: "nil NodeAffinityScoring passes validation",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: &plugins.Plugins{
						NodeAffinityScoring: nil,
					},
				},
			},
			wantErr: false,
		},
		{
			name: "unique architectures passes validation",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: &plugins.Plugins{
						NodeAffinityScoring: &plugins.NodeAffinityScoring{
							Platforms: []plugins.NodeAffinityScoringPlatformTerm{
								{Architecture: "amd64", Weight: 50},
								{Architecture: "arm64", Weight: 50},
							},
						},
					},
				},
			},
			wantErr: false,
		},
		{
			name: "duplicate architectures fails validation",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: &plugins.Plugins{
						NodeAffinityScoring: &plugins.NodeAffinityScoring{
							Platforms: []plugins.NodeAffinityScoringPlatformTerm{
								{Architecture: "amd64", Weight: 50},
								{Architecture: "amd64", Weight: 80},
							},
						},
					},
				},
			},
			wantErr: true,
		},
		{
			name: "single architecture passes validation",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: &plugins.Plugins{
						NodeAffinityScoring: &plugins.NodeAffinityScoring{
							Platforms: []plugins.NodeAffinityScoringPlatformTerm{
								{Architecture: "arm64", Weight: 100},
							},
						},
					},
				},
			},
			wantErr: false,
		},
		{
			name: "multiple duplicates fails validation",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: &plugins.Plugins{
						NodeAffinityScoring: &plugins.NodeAffinityScoring{
							Platforms: []plugins.NodeAffinityScoringPlatformTerm{
								{Architecture: "amd64", Weight: 50},
								{Architecture: "arm64", Weight: 50},
								{Architecture: "amd64", Weight: 80},
							},
						},
					},
				},
			},
			wantErr: true,
		},
	}

	for _, tt := range tests {
		t.Run("ValidateCreate/"+tt.name, func(t *testing.T) {
			_, err := validator.ValidateCreate(context.Background(), tt.cppc)
			if (err != nil) != tt.wantErr {
				t.Errorf("ValidateCreate() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
		t.Run("ValidateUpdate/"+tt.name, func(t *testing.T) {
			_, err := validator.ValidateUpdate(context.Background(), nil, tt.cppc)
			if (err != nil) != tt.wantErr {
				t.Errorf("ValidateUpdate() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
	}
}
